import { useEffect, useMemo, useState } from "react";
import { FiAlertCircle, FiClock, FiDollarSign, FiPackage, FiShoppingBag } from "react-icons/fi";
import PageState from "../components/PageState";
import axios from "../utils/axios";
import { extractList, extractOne } from "../utils/apiShape";

const formatCurrency = (value) => `Tsh ${Number(value || 0).toLocaleString()}`;

export default function VendorDashboard() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [profile, setProfile] = useState(null);
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [summary, setSummary] = useState({ totalRevenue: 0, totalOrders: 0, pendingOrders: 0 });

  useEffect(() => {
    const loadDashboard = async () => {
      setLoading(true);
      try {
        const [profileResponse, productsResponse, ordersResponse] = await Promise.all([
          axios.get("/vendor/profile"),
          axios.get("/vendor/products"),
          axios.get("/vendor/orders"),
        ]);

        setProfile(extractOne(profileResponse.data));
        setProducts(extractList(productsResponse.data, ["products", "items"]));
        setOrders(extractList(ordersResponse.data, ["orders", "items"]));
        setSummary(
          extractOne(ordersResponse.data)?.summary || {
            totalRevenue: 0,
            totalOrders: 0,
            pendingOrders: 0,
          }
        );
        setError("");
      } catch (err) {
        console.error(err);
        setError(err.response?.data?.message || "Failed to load vendor dashboard.");
      } finally {
        setLoading(false);
      }
    };

    loadDashboard();
  }, []);

  const metrics = useMemo(() => {
    const approvedCount = products.filter((product) => product.status === "approved").length;
    const pendingCount = products.filter((product) => product.status === "pending").length;
    const lowStockCount = products.filter((product) => Number(product.stock || 0) <= 5).length;

    return [
      {
        title: "Store Revenue",
        value: formatCurrency(summary.totalRevenue),
        note: "Sales generated by your items",
        icon: FiDollarSign,
      },
      {
        title: "Active Products",
        value: approvedCount,
        note: `${products.length} total in your catalog`,
        icon: FiPackage,
      },
      {
        title: "Orders Received",
        value: summary.totalOrders,
        note: `${summary.pendingOrders} still waiting`,
        icon: FiShoppingBag,
      },
      {
        title: "Needs Attention",
        value: pendingCount + lowStockCount,
        note: `${pendingCount} pending review, ${lowStockCount} low stock`,
        icon: FiClock,
      },
    ];
  }, [products, summary]);

  if (loading) {
    return <PageState title="Loading vendor workspace" description="Preparing your store overview..." />;
  }

  if (error) {
    return <PageState tone="error" title="Vendor dashboard unavailable" description={error} />;
  }

  return (
    <div className="space-y-5 md:space-y-6">
      <section className="rounded-[30px] border border-[#102A43]/10 bg-[linear-gradient(135deg,#ffffff_0%,#eff6ff_46%,#fff7ed_100%)] p-5 shadow-[0_24px_50px_rgba(15,23,42,0.08)] md:p-6">
        <p className="text-[11px] font-semibold uppercase tracking-[0.28em] text-[#102A43]">Vendor Overview</p>
        <div className="mt-3 flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
          <div>
            <h1 className="text-2xl font-black text-slate-900 md:text-3xl">
              {profile?.storeName || "Set up your store"}
            </h1>
            <p className="mt-2 max-w-2xl text-sm text-slate-600 md:text-base">
              Track products, incoming orders, and store performance from one clean workspace.
            </p>
          </div>
          <div className="rounded-2xl border border-orange-200/70 bg-white/80 px-4 py-3 text-sm text-slate-600 shadow-sm">
            <p className="font-semibold text-slate-900">Store slug</p>
            <p>
              {profile?.storeSlug
                ? `/${profile.storeSlug}`
                : "Add your store profile to create a branded storefront."}
            </p>
          </div>
        </div>
      </section>

      <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        {metrics.map((item) => {
          const Icon = item.icon;
          return (
            <article
              key={item.title}
              className="rounded-[26px] border border-white/80 bg-white/90 p-5 shadow-[0_18px_38px_rgba(15,23,42,0.06)]"
            >
              <div className="flex items-start justify-between gap-3">
                <div>
                  <p className="text-xs font-semibold uppercase tracking-[0.24em] text-slate-400">
                    {item.title}
                  </p>
                  <p className="mt-3 text-2xl font-black text-slate-900">{item.value}</p>
                </div>
                <span className="rounded-2xl bg-orange-50 p-3 text-orange-600">
                  <Icon size={18} />
                </span>
              </div>
              <p className="mt-3 text-sm text-slate-500">{item.note}</p>
            </article>
          );
        })}
      </section>

      <section className="grid gap-5 xl:grid-cols-[1.15fr_0.85fr]">
        <div className="surface-panel-lg p-5">
          <p className="text-[11px] font-semibold uppercase tracking-[0.24em] text-[#102A43]">Latest Orders</p>
          <h2 className="mt-1 text-lg font-black text-slate-900">Recent sales activity</h2>

          <div className="mt-4 space-y-3">
            {orders.slice(0, 4).map((order) => (
              <article key={order._id} className="rounded-2xl border border-slate-100 bg-slate-50/80 p-4">
                <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                  <div>
                    <p className="text-sm font-semibold text-slate-900">Order #{order._id}</p>
                    <p className="text-sm text-slate-500">
                      {order.user?.name || "Customer"} • {order.items.length} item(s)
                    </p>
                  </div>
                  <div className="text-left sm:text-right">
                    <span className="inline-flex rounded-full bg-orange-50 px-3 py-1 text-xs font-semibold text-orange-700">
                      {order.status.replace(/_/g, " ")}
                    </span>
                    <p className="mt-2 text-sm font-semibold text-slate-900">
                      {formatCurrency(order.vendorSummary?.subtotal)}
                    </p>
                  </div>
                </div>
              </article>
            ))}

            {!orders.length ? (
              <PageState
                tone="info"
                title="No orders yet"
                description="Once customers buy your approved products, they will appear here."
              />
            ) : null}
          </div>
        </div>

        <div className="surface-panel-lg p-5">
          <p className="text-[11px] font-semibold uppercase tracking-[0.24em] text-[#102A43]">Catalog Snapshot</p>
          <h2 className="mt-1 text-lg font-black text-slate-900">Product readiness</h2>

          <div className="mt-4 space-y-3">
            {products.slice(0, 5).map((product) => (
              <div
                key={product._id}
                className="flex items-center justify-between rounded-2xl border border-slate-100 bg-slate-50/80 px-4 py-3"
              >
                <div>
                  <p className="text-sm font-semibold text-slate-900">{product.name}</p>
                  <p className="text-xs text-slate-500">
                    {formatCurrency(product.price)} • {product.stock} in stock
                  </p>
                </div>
                <span
                  className={`rounded-full px-3 py-1 text-xs font-semibold ${
                    product.status === "approved"
                      ? "bg-emerald-100 text-emerald-700"
                      : product.status === "rejected"
                        ? "bg-red-100 text-red-700"
                        : "bg-orange-100 text-orange-700"
                  }`}
                >
                  {product.status}
                </span>
              </div>
            ))}

            {!products.length ? (
              <div className="rounded-2xl border border-dashed border-orange-200 bg-orange-50/70 px-4 py-4 text-sm text-slate-600">
                <div className="flex items-center gap-2 font-semibold text-slate-900">
                  <FiAlertCircle className="text-orange-500" />
                  Start by adding your first product
                </div>
                <p className="mt-1">Products you submit will stay pending until admin review is complete.</p>
              </div>
            ) : null}
          </div>
        </div>
      </section>
    </div>
  );
}
